function normalizarCalle(nombre) {
  return nombre.toLowerCase()
    .replace(/á/g, "a").replace(/é/g, "e").replace(/í/g, "i")
    .replace(/ó/g, "o").replace(/ú/g, "u").replace(/ñ/g, "n")
    .replace(/^(av\.|avenida|calle|pasaje)\s+/g, "")
    .trim();
}

