function distancia(a, b) {
  const dlat = a.lat - b.lat;
  const dlon = a.lon - b.lon;
  return Math.sqrt(dlat * dlat + dlon * dlon);
}

function nearestNeighbor(puntoInicio, paradas) {
  const pendientes = [...paradas];
  const ordenadas  = [];
  let actual = puntoInicio;
  while (pendientes.length > 0) {
    let minDist = Infinity, minIdx = 0;
    for (let i = 0; i < pendientes.length; i++) {
      const coords = buscarCoords(pendientes[i]);
      if (!coords) continue;
      const d = distancia(actual, coords);
      if (d < minDist) { minDist = d; minIdx = i; }
    }
    const siguiente = pendientes.splice(minIdx, 1)[0];
    ordenadas.push(siguiente);
    actual = buscarCoords(siguiente) || actual;
  }
  return ordenadas;
}

