    const diaBD = (p.json.dia || '').toLowerCase()
      .replace(/á/g, 'a').replace(/é/g, 'e').replace(/í/g, 'i')
      .replace(/ó/g, 'o').replace(/ú/g, 'u');
    return diaBD === diaHoy;
  });

  if (filasDia.length > 0) {
    const placas = filasDia[0].json.digitos_placa;
    const placasTexto = Array.isArray(placas) ? placas.join(', ') : placas;
    const franjas = filasDia.map(p => `${p.json.hora_inicio} - ${p.json.hora_fin}`).join(' y ');
    picoPlacaTexto = `Placas terminadas en ${placasTexto} NO pueden circular en los horarios: ${franjas}.`;
  }
}
// ── Zonas rojas activas ───────────────────────────
let zonasTexto = 'No hay zonas de riesgo activas en este horario.';
if (zonasItems.length > 0) {
  const horaOperacion = webhook.hora_inicio;

  const zonasActivas = zonasItems.filter(z => {
    const horaInicio = z.json.hora_inicio.substring(0, 5);
    const horaFin = z.json.hora_fin.substring(0, 5);
    if (horaInicio > horaFin) {
      return horaOperacion >= horaInicio || horaOperacion <= horaFin;
    } else {
      return horaOperacion >= horaInicio && horaOperacion <= horaFin;
    }
  });

  if (zonasActivas.length > 0) {
    const lineas = zonasActivas.map(z => {
      return `- ${z.json.nombre_zona} (riesgo ${z.json.nivel_riesgo})`;
    });
    zonasTexto = lineas.join('\n');
  }
}



// ── Conductores disponibles ───────────────────────
let conductoresTexto = 'Sin datos de conductores.';
if (conductoresItems.length > 0) {
  const diaHoy = webhook.dia_label.toLowerCase()
    .replace(/á/g, 'a').replace(/é/g, 'e').replace(/í/g, 'i')
    .replace(/ó/g, 'o').replace(/ú/g, 'u');

  const filasDia = picoPlacaItems.filter(p => {
    const diaBD = (p.json.dia || '').toLowerCase()
      .replace(/á/g, 'a').replace(/é/g, 'e').replace(/í/g, 'i')
      .replace(/ó/g, 'o').replace(/ú/g, 'u');
    return diaBD === diaHoy;
  });

  const lineas = conductoresItems
    .filter((item, index, self) =>
      index === self.findIndex(t => t.json.conductor_id === item.json.conductor_id)
    )
    .map(c => {
      const conductor = c.json;
      const dias = Array.isArray(conductor.dias_disponibles)
        ? conductor.dias_disponibles.join(', ')
        : conductor.dias_disponibles;

      const descripcion = conductor.descripcion || '';
      const matchPlaca = descripcion.match(/placas?\s+terminadas?\s+en\s+([\d\s,y]+)/i);
      const digitosPlaca = matchPlaca
        ? matchPlaca[1].match(/\d/g) || []
        : [];

      let estadoPP = 'sin restricción de pico y placa';

      if (digitosPlaca.length === 0) {
        estadoPP = 'placa no identificada en descripción';
      } else if (filasDia.length > 0) {
        const placasRestringidas = filasDia[0].json.digitos_placa;
        const placasArray = Array.isArray(placasRestringidas)
          ? placasRestringidas.map(String)
          : String(placasRestringidas).split(',').map(s => s.trim());

        const franjas = filasDia
          .map(p => `${p.json.hora_inicio}-${p.json.hora_fin}`)
          .join(' y ');

        if (digitosPlaca.some(d => placasArray.includes(d))) {
          estadoPP = `RESTRICCIÓN PICO Y PLACA (placa termina en ${digitosPlaca.join(' o ')}, restringido hoy ${franjas})`;
        }
      }

      return `- ${conductor.conductor_id}: ${conductor.vehiculo_tipo}, ` +
             `${conductor.hora_inicio}-${conductor.hora_fin}, ` +
             `días: ${dias}, estado_pp: ${estadoPP}`;
    });

  conductoresTexto = lineas.length > 0
    ? lineas.join('\n')
    : 'Ningún conductor coincide.';
}
// ── Kg por KFC — solo zona seleccionada ──────────
let kgTexto = '';
if (kgItems.length > 0) {
  const zonaSeleccionada = webhook.zona ? webhook.zona.toLowerCase() : '';

  const zonaKeywords = {
    'norte': ['mitad del mundo','carcelén','calderón','llano grande','portal','carapungo','condado','prensa','comité','eloy alfaro','molineros','cotocollao'],
    'centro-norte': ['américas','inca','quicentro norte','cci','jardín','colón','baca ortiz'],
    'centro': ['iess','patria','san francisco','coral'],
    'sur': ['recreo','michelena','shell sur','chillogallo','quitumbe'],
    'valles': ['san rafael','sangolquí','guamaní','mega santa','cumbayá']
  };

  if (zonaSeleccionada === 'todas' || zonaSeleccionada === '') {
    kgTexto = 'Norte ~1200kg, Centro-Norte ~900kg, Centro ~400kg, Sur ~700kg, Valles ~600kg.';
  } else {
    let keywordsActivos = [];
    const zonasArray = zonaSeleccionada.split(',').map(z => z.trim());
    zonasArray.forEach(z => {
      if (zonaKeywords[z]) keywordsActivos = keywordsActivos.concat(zonaKeywords[z]);
    });

    const kfcsFiltrados = kgItems.filter(k => {
      const nombre = k.json.nombre_kfc ? k.json.nombre_kfc.toLowerCase() : '';
      return keywordsActivos.some(kw => nombre.includes(kw));
    });

    const totalKg = kfcsFiltrados.reduce((sum, k) => sum + (k.json.kg_promedio || 0), 0);
    const lineas = kfcsFiltrados.map(k => `- ${k.json.nombre_kfc}: ${k.json.kg_promedio}kg`);
    kgTexto = lineas.join('\n') + `\nTOTAL ESTIMADO: ${totalKg}kg`;
  }
}

// ── Contexto final compacto ───────────────────────
const contextoRAG = `=== CONTEXTO OPERACIONAL ===
DÍA: ${webhook.dia_label} | HORA: ${webhook.hora_inicio}-${webhook.hora_fin} | ZONA: ${webhook.zona_label}
FLOTA: ${webhook.flota}
FLOTA CON ESTADO CALCULADO (USA ESTO PARA DECISIONES DE PICO Y PLACA):
${webhook.flota}
VEHÍCULOS: ${webhook.num_vehiculos} | CAPACIDAD: ${webhook.capacidad_total}kg | NOCTURNA: ${webhook.operacion_nocturna ? 'SÍ' : 'NO'}
PICO Y PLACA: ${picoPlacaTexto}
ZONAS RIESGO ACTIVAS:
${zonasTexto}
CONDUCTORES SELECCIONADOS:
${conductoresTexto}
KG POR KFC:
${kgTexto}
=== FIN CONTEXTO ===`;

return [{
  json: {
    ...webhook,
    contextoRAG: contextoRAG
  }
}];
